// --- Dynamic colors (injected from config.py palette) ---
const COLORS = '__DATA_COLORS__';
const COLORS_DARK = Object.assign({}, COLORS);
// Light-theme palette: darker variants that pass AA-normal (4.5:1) on #f6f8fa
const DARK_TO_LIGHT = {
  '#f97316': '#c05621',
  '#3b82f6': '#2563eb',
  '#b975f9': '#7c3aed',
  '#22c55e': '#15803d',
  '#eab308': '#a16207',
  '#ec4899': '#be185d',
  '#14b8a6': '#0f766e',
  '#f43f5e': '#be123c',
};
const COLORS_LIGHT = {};
Object.entries(COLORS_DARK).forEach(([k, v]) => {
  COLORS_LIGHT[k] = DARK_TO_LIGHT[v] || v;
});
const COLORS_PALE = {};
function applyPalette() {
  var src = getTheme() === 'light' ? COLORS_LIGHT : COLORS_DARK;
  Object.keys(src).forEach((k) => {
    COLORS[k] = src[k];
  });
  Object.entries(COLORS).forEach(([k, v]) => {
    COLORS_PALE[k] = v + '44';
  });
}
applyPalette();

// Non-color differentiators (WCAG 1.4.1 Use of Color)
var POINT_STYLES_OTHER = [
  'triangle',
  'rect',
  'rectRot',
  'star',
  'cross',
  'crossRot',
  'dash',
];
function hatchPattern(bgColor, type) {
  if (!type) return bgColor;
  var s = 8,
    c = document.createElement('canvas');
  c.width = s;
  c.height = s;
  var x = c.getContext('2d');
  x.fillStyle = bgColor;
  x.fillRect(0, 0, s, s);
  x.strokeStyle = 'rgba(255,255,255,0.35)';
  x.lineWidth = 1.5;
  if (type === 1) {
    x.beginPath();
    x.moveTo(0, 0);
    x.lineTo(s, s);
    x.moveTo(-2, s - 2);
    x.lineTo(2, s + 2);
    x.moveTo(s - 2, -2);
    x.lineTo(s + 2, 2);
    x.stroke();
  } else if (type === 2) {
    x.beginPath();
    x.moveTo(s, 0);
    x.lineTo(0, s);
    x.moveTo(s + 2, s - 2);
    x.lineTo(s - 2, s + 2);
    x.moveTo(2, -2);
    x.lineTo(-2, 2);
    x.stroke();
  } else if (type === 3) {
    x.beginPath();
    x.moveTo(0, s / 2);
    x.lineTo(s, s / 2);
    x.stroke();
  } else if (type === 4) {
    x.beginPath();
    x.moveTo(s / 2, 0);
    x.lineTo(s / 2, s);
    x.stroke();
  } else if (type === 5) {
    x.beginPath();
    x.moveTo(0, 0);
    x.lineTo(s, s);
    x.moveTo(s, 0);
    x.lineTo(0, s);
    x.stroke();
  } else if (type === 6) {
    x.fillStyle = 'rgba(255,255,255,0.35)';
    x.beginPath();
    x.arc(s / 2, s / 2, 1.5, 0, Math.PI * 2);
    x.fill();
  } else if (type === 7) {
    x.beginPath();
    x.moveTo(0, s / 2);
    x.lineTo(s, s / 2);
    x.moveTo(s / 2, 0);
    x.lineTo(s / 2, s);
    x.stroke();
  }
  return x.createPattern(c, 'repeat');
}

// --- Shared chart helpers ---

// Create solid + pale dataset pair for a major version
function makeDatasetPair(major, solidData, paleData, suffix, stack) {
  const c = COLORS[major];
  return [
    {
      label: major,
      data: solidData,
      backgroundColor: c + 'cc',
      borderColor: c,
      borderWidth: 1,
      borderRadius: 3,
      stack,
    },
    {
      label: major + suffix,
      data: paleData,
      backgroundColor: COLORS_PALE[major],
      borderColor: c + '88',
      borderWidth: 1,
      borderRadius: 3,
      stack,
    },
  ];
}

// Convert stacked + fixonly data to percentage-based datasets
function pctDatasets(stacked, fixonly, suffix) {
  return majorsOrder.flatMap((m) => {
    const total =
      stacked[m].reduce((s, v) => s + v, 0) +
      fixonly[m].reduce((s, v) => s + v, 0);
    const toPct = (arr) =>
      arr.map((v) => (total > 0 ? +((v / total) * 100).toFixed(1) : 0));
    return makeDatasetPair(m, toPct(stacked[m]), toPct(fixonly[m]), suffix, m);
  });
}

// Factory for stacked bar charts (covers week, weekNotes, dow, hour)
function stackedBar(id, labels, datasets, opts = {}) {
  const tooltipCb = {};
  if (opts.tooltipTitle) tooltipCb.title = opts.tooltipTitle;
  if (opts.tooltipLabel) tooltipCb.label = opts.tooltipLabel;
  if (opts.tooltipFooter) tooltipCb.footer = opts.tooltipFooter;
  return new Chart(document.getElementById(id), {
    type: 'bar',
    data: { labels, datasets },
    options: {
      responsive: true,
      maintainAspectRatio: false,
      plugins: {
        legend: {
          position: 'top',
          labels: { boxWidth: 12, padding: opts.legendPad || 16 },
        },
        tooltip: {
          mode: 'index',
          filter: (i) => i.parsed.y !== 0,
          callbacks: tooltipCb,
        },
      },
      scales: {
        x: { stacked: true, grid: { display: false }, ...(opts.xScale || {}) },
        y: {
          stacked: true,
          beginAtZero: true,
          ...(opts.yTitle
            ? { title: { display: true, text: opts.yTitle } }
            : {}),
          ...(opts.yTicks ? { ticks: opts.yTicks } : {}),
          ...(opts.yExtra || {}),
        },
      },
    },
  });
}

// Tooltip footer that sums all visible items
function totalFooter(unit) {
  return (items) => {
    const t = items.reduce((s, i) => s + i.parsed.y, 0);
    return `Total: ${t} ${unit}`;
  };
}

const THEME_CHART = {
  dark: { text: '#8b949e', border: '#30363d', heading: '#f0f6fc' },
  light: { text: '#656d76', border: '#d0d7de', heading: '#1f2328' },
};
function getTheme() {
  return document.documentElement.getAttribute('data-theme') || 'dark';
}
function applyChartTheme() {
  const t = THEME_CHART[getTheme()];
  Chart.defaults.color = t.text;
  Chart.defaults.borderColor = t.border;
}
applyChartTheme();
if (window.matchMedia('(prefers-reduced-motion: reduce)').matches) {
  Chart.defaults.animation = false;
}
Chart.defaults.font.family =
  '-apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif';

// Plugin: label first appearance of each version series above bars
Chart.register({
  id: 'seriesLabels',
  afterDraw: function (chart) {
    var sl = chart._seriesLabels;
    if (!sl) return;
    var ctx = chart.ctx;
    var t = THEME_CHART[getTheme()];
    ctx.save();
    ctx.textAlign = 'center';
    ctx.textBaseline = 'top';
    ctx.font = 'bold 10px -apple-system, BlinkMacSystemFont, sans-serif';
    ctx.fillStyle = t.heading;
    sl.forEach(function (s) {
      var xPos = chart.scales.x.getPixelForValue(
        new Date(chart.data.labels[s.index]).getTime(),
      );
      if (xPos >= chart.chartArea.left && xPos <= chart.chartArea.right) {
        ctx.fillText(s.label, xPos, chart.chartArea.top + 4);
      }
    });
    ctx.restore();
  },
});

function findFirstAppearances(stacked, fixonly) {
  return majorsOrder
    .map(function (m) {
      for (var i = 0; i < weekLabels.length; i++) {
        if ((stacked[m][i] || 0) + (fixonly[m][i] || 0) > 0)
          return { label: m, index: i };
      }
      return null;
    })
    .filter(Boolean);
}

