// Outlier detection: find >2x gap and compute y-axis cap
function computeOutlierCap(totals, maxOutliers = 3) {
  const desc = totals.slice().sort((a, b) => b - a);
  let threshold = desc[0] + 1;
  for (let i = 0; i < desc.length - 1 && i < maxOutliers; i++) {
    if (desc[i] > desc[i + 1] * 2) {
      threshold = desc[i + 1] * 2;
      break;
    }
  }
  const cap =
    Math.ceil(
      Math.min(desc.find((v) => v <= threshold) || desc[0], threshold) / 5,
    ) *
      5 +
    5;
  return { threshold, cap };
}

// Helpers: compute visible totals and per-bar fix/non-fix from chart state
function getVisibleTotals(chart) {
  return notesData.map((_, i) => {
    let sum = 0;
    chart.data.datasets.forEach((ds, dsIdx) => {
      if (!chart.getDatasetMeta(dsIdx).hidden) sum += ds.data[i] || 0;
    });
    return sum;
  });
}
function getVisibleParts(chart, idx) {
  let fixes = 0,
    nonFixes = 0;
  chart.data.datasets.forEach((ds, dsIdx) => {
    if (chart.getDatasetMeta(dsIdx).hidden) return;
    const val = ds.data[idx] || 0;
    if (ds.label.includes('(fixes)')) fixes += val;
    else nonFixes += val;
  });
  return { fixes, nonFixes, total: fixes + nonFixes };
}

// DOM setup: overlay container + tooltip
const notesCanvas = document.getElementById('notesChart');
const notesWrapper = notesCanvas.parentElement;
notesWrapper.style.overflow = 'visible';
notesWrapper.parentElement.style.overflow = 'visible';
const notesOverlayContainer = document.createElement('div');
notesOverlayContainer.className = 'overlay-container';
notesWrapper.appendChild(notesOverlayContainer);
const overlayTooltip = document.createElement('div');
overlayTooltip.className = 'overlay-tooltip';
overlayTooltip.setAttribute('role', 'status');
overlayTooltip.setAttribute('aria-live', 'polite');
document.body.appendChild(overlayTooltip);
// Sentinel at bottom of chart for scroll detection
const notesSentinel = document.createElement('div');
notesSentinel.style.cssText =
  'position:absolute;bottom:0;left:0;width:1px;height:1px';
notesWrapper.appendChild(notesSentinel);

// Track focused overlay version for focus restoration after rebuild
var focusedOverlayVersion = null;

// Show ALL outlier overlays at once
function showNotesOverlays(chart) {
  const o = chart._outlier;
  const meta = chart.getDatasetMeta(0);
  const { chartArea } = chart;
  const pxPerUnit = (chartArea.bottom - chartArea.top) / o.cap;
  var restoreVersion = focusedOverlayVersion;
  while (notesOverlayContainer.firstChild)
    notesOverlayContainer.removeChild(notesOverlayContainer.firstChild);
  o.visibleTotals.forEach((total, idx) => {
    if (total <= o.threshold || !meta.data[idx]) return;
    const parts = getVisibleParts(chart, idx);
    if (parts.total <= o.cap) return;
    const overflowPx = (parts.total - o.cap) * pxPerUnit;
    const barWidth = meta.data[idx].width || 8;
    const barX = meta.data[idx].x;
    const major = notesData[idx].major;
    const color = COLORS[major];
    const version = notesData[idx].version;

    const col = document.createElement('div');
    col.className = 'overlay-col';
    col.style.left = barX - barWidth / 2 + 'px';
    col.style.top = chartArea.top - overflowPx - 20 + 'px';
    col.style.width = barWidth + 'px';
    col.setAttribute('tabindex', '0');
    col.setAttribute('role', 'img');
    col.setAttribute(
      'aria-label',
      version +
        ': ' +
        parts.nonFixes +
        ' non-fix changes, ' +
        parts.fixes +
        ' fixes, ' +
        parts.total +
        ' total',
    );
    col.addEventListener('mouseenter', () => {
      overlayTooltip.textContent =
        version +
        '\nnon-fix changes: ' +
        parts.nonFixes +
        '\nfixes: ' +
        parts.fixes +
        '\nTotal: ' +
        parts.total;
      overlayTooltip.style.display = 'block';
    });
    col.addEventListener('mousemove', (e) => {
      overlayTooltip.style.left = e.clientX + 12 + 'px';
      overlayTooltip.style.top = e.clientY + 12 + 'px';
    });
    col.addEventListener('mouseleave', () => {
      overlayTooltip.style.display = 'none';
    });
    col.addEventListener('focus', function () {
      focusedOverlayVersion = version;
      overlayTooltip.textContent =
        version +
        '\nnon-fix changes: ' +
        parts.nonFixes +
        '\nfixes: ' +
        parts.fixes +
        '\nTotal: ' +
        parts.total;
      overlayTooltip.style.display = 'block';
      var r = this.getBoundingClientRect();
      var left = r.right + 8;
      if (left + 220 > window.innerWidth) left = r.left - 228;
      overlayTooltip.style.left = Math.max(0, left) + 'px';
      overlayTooltip.style.top = r.top + 'px';
    });
    col.addEventListener('blur', function () {
      focusedOverlayVersion = null;
      overlayTooltip.style.display = 'none';
    });

    const label = document.createElement('div');
    label.className = 'overlay-label';
    label.textContent = String(parts.total);
    label.style.marginLeft = '-10px';
    label.style.width = barWidth + 20 + 'px';
    col.appendChild(label);

    if (parts.fixes > 0) {
      const el = document.createElement('div');
      el.className = 'overlay-segment';
      el.style.cssText = `width:${barWidth}px;height:${parts.fixes * pxPerUnit}px;background:${COLORS_PALE[major]};border:1px solid ${color}88;border-bottom:0`;
      col.appendChild(el);
    }
    if (parts.nonFixes > 0) {
      const el = document.createElement('div');
      el.className = 'overlay-segment';
      el.style.cssText = `width:${barWidth}px;height:${parts.nonFixes * pxPerUnit}px;background:${color}cc;border:1px solid ${color};border-top:0`;
      col.appendChild(el);
    }
    notesOverlayContainer.appendChild(col);
  });
  notesOverlayContainer.style.display = 'block';
  if (restoreVersion) {
    var el = notesOverlayContainer.querySelector(
      '[aria-label^="' + restoreVersion + ':"]',
    );
    if (el) el.focus();
  }
}
function hideNotesOverlays() {
  notesOverlayContainer.style.display = 'none';
}

// Plugin: draw static outlier labels above capped bars
const notesOutlierPlugin = {
  id: 'notesOutlierLabels',
  afterDraw(chart) {
    const o = chart._outlier;
    if (!o) return;
    const { ctx, chartArea } = chart;
    const meta = chart.getDatasetMeta(0);
    o.visibleTotals.forEach((total, i) => {
      if (total <= o.threshold || o.hovered || !meta.data[i]) return;
      const x = meta.data[i].x;
      ctx.save();
      ctx.fillStyle = THEME_CHART[getTheme()].heading;
      ctx.textAlign = 'center';
      ctx.font = 'bold 11px -apple-system, BlinkMacSystemFont, sans-serif';
      ctx.textBaseline = 'bottom';
      ctx.fillText(String(total), x, chartArea.top - 10);
      ctx.font = '10px -apple-system, BlinkMacSystemFont, sans-serif';
      ctx.textBaseline = 'top';
      ctx.fillText('\u25B4', x, chartArea.top - 10);
      ctx.restore();
    });
  },
};

// Create notes chart with outlier capping
const notesInit = computeOutlierCap(notesData.map((d) => d.total));
const notesChart = new Chart(notesCanvas, {
  type: 'bar',
  data: { labels: notesLabels, datasets: notesDatasets },
  plugins: [notesOutlierPlugin],
  options: {
    responsive: true,
    maintainAspectRatio: false,
    onResize(chart) {
      const o = chart._outlier;
      if (o && o.hovered) requestAnimationFrame(() => showNotesOverlays(chart));
    },
    layout: { padding: { top: 20 } },
    plugins: {
      legend: {
        position: 'top',
        labels: { boxWidth: 12, padding: 16 },
        onClick(e, legendItem) {
          const idx = legendItem.datasetIndex;
          const meta = notesChart.getDatasetMeta(idx);
          meta.hidden =
            meta.hidden === null ? !notesChart.data.datasets[idx].hidden : null;
          const totals = getVisibleTotals(notesChart);
          const result = computeOutlierCap(totals);
          const inView =
            notesSentinel.getBoundingClientRect().bottom <= window.innerHeight;
          notesChart._outlier = {
            threshold: result.threshold,
            cap: result.cap,
            visibleTotals: totals,
            hovered: inView,
          };
          notesChart.options.scales.y.max = result.cap;
          hideNotesOverlays();
          notesChart.update('none');
          if (inView) showNotesOverlays(notesChart);
        },
      },
      tooltip: {
        mode: 'index',
        filter: (item) => item.parsed.y !== 0,
        callbacks: {
          title: (items) => notesData[items[0].dataIndex].version,
          label: (item) => {
            const kind = item.dataset.label.includes('(fixes)')
              ? 'fixes'
              : 'non-fix changes';
            return kind + ': ' + item.parsed.y;
          },
          footer: (items) => {
            const parts = getVisibleParts(notesChart, items[0].dataIndex);
            return `Total: ${parts.total}`;
          },
        },
      },
    },
    scales: {
      x: {
        stacked: true,
        grid: { display: false },
        ticks: {
          autoSkip: false,
          maxRotation: 0,
          font: { size: 10 },
          callback: function (val, idx) {
            const cur = notesData[idx].major;
            return cur !== (idx > 0 ? notesData[idx - 1].major : null)
              ? cur
              : '';
          },
        },
      },
      y: {
        stacked: true,
        title: { display: true, text: 'Bullet points' },
        beginAtZero: true,
        max: notesInit.cap,
      },
    },
  },
});
notesChart._outlier = {
  threshold: notesInit.threshold,
  cap: notesInit.cap,
  visibleTotals: notesData.map((d) => d.total),
  hovered: false,
};

// Scroll-to-reveal: show overlays when chart bottom is visible
new IntersectionObserver(
  (entries) => {
    const o = notesChart._outlier;
    const visible = entries[0].isIntersecting;
    if (visible !== o.hovered) {
      o.hovered = visible;
      if (visible) showNotesOverlays(notesChart);
      else hideNotesOverlays();
      notesChart.draw();
    }
  },
  { threshold: 1.0 },
).observe(notesSentinel);

// --- Major version table ---
const notesTotalByMajor = {};
notesData.forEach((d) => {
  notesTotalByMajor[d.major] = (notesTotalByMajor[d.major] || 0) + d.total;
});
const tbody = document.getElementById('major-table-body');
majorsOrder.forEach((series) => {
  const s = majorStats[series];
  const perWeek =
    s.span_days > 0 ? (s.count / (s.span_days / 7)).toFixed(1) : '\u2014';
  const notesTotal = notesTotalByMajor[series] || 0;
  const notesPerWeek =
    s.span_days > 0 && notesTotal > 0
      ? (notesTotal / (s.span_days / 7)).toFixed(1)
      : '\u2014';
  const tr = document.createElement('tr');
  const tdSeries = document.createElement('td');
  const dot = document.createElement('span');
  dot.className = 'color-dot';
  dot.style.background = COLORS[series];
  dot.setAttribute('aria-hidden', 'true');
  tdSeries.appendChild(dot);
  tdSeries.appendChild(document.createTextNode(series));
  tr.appendChild(tdSeries);
  [
    s.count,
    s.span_days + ' days',
    perWeek,
    notesPerWeek,
    s.first + ' \u2014 ' + s.last,
  ].forEach((text) => {
    const td = document.createElement('td');
    td.textContent = String(text);
    tr.appendChild(td);
  });
  tbody.appendChild(tr);
});

// --- Heatmap (DOW x Hour, pure CSS grid — wide + narrow layouts) ---
(function () {
  const container = document.getElementById('heatmap');
  const dayNames = ['Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat', 'Sun'];
  const maxVal = Math.max(1, ...heatmapDowHour.flat());

  // Tooltip element (shared)
  const tip = document.createElement('div');
  tip.className = 'heatmap-cell-tooltip';
  tip.setAttribute('role', 'status');
  tip.setAttribute('aria-live', 'polite');
  document.body.appendChild(tip);

  function cellTipText(cell) {
    var dn = dayNames[+cell.dataset.dow];
    var hr = +cell.dataset.hour;
    var hrLabel = (hr % 12 || 12) + (hr < 12 ? 'am' : 'pm');
    return (
      dn +
      ' ' +
      hrLabel +
      ': ' +
      cell.dataset.total +
      ' entries (' +
      cell.dataset.fixes +
      ' fixes, ' +
      cell.dataset.features +
      ' features)'
    );
  }

  function showTipAt(el) {
    tip.textContent = cellTipText(el);
    tip.style.display = 'block';
    var r = el.getBoundingClientRect();
    var left = r.right + 8;
    if (left + 220 > window.innerWidth) left = r.left - 228;
    tip.style.left = Math.max(0, left) + 'px';
    tip.style.top = r.top + 'px';
  }

  function makeCell(d, h, isFirst) {
    const total = heatmapDowHour[d][h];
    const fixes = heatmapDowHourFixes[d][h];
    const features = total - fixes;
    const intensity = total > 0 ? Math.sqrt(total / maxVal) : 0;
    const cell = document.createElement('div');
    cell.className = 'heatmap-cell';
    cell.setAttribute('role', 'gridcell');
    cell.setAttribute('tabindex', isFirst ? '0' : '-1');
    const isDark = getTheme() === 'dark';
    cell.dataset.dow = d;
    cell.dataset.hour = h;
    cell.dataset.total = total;
    cell.dataset.fixes = fixes;
    cell.dataset.features = features;
    var dn = dayNames[d];
    var hrLabel = (h % 12 || 12) + (h < 12 ? 'am' : 'pm');
    cell.setAttribute(
      'aria-label',
      dn +
        ' ' +
        hrLabel +
        ': ' +
        total +
        ' entries (' +
        fixes +
        ' fixes, ' +
        features +
        ' features)',
    );
    if (total === 0) {
      cell.style.background = isDark
        ? 'rgba(255,255,255,0.03)'
        : 'rgba(0,0,0,0.03)';
    } else {
      cell.style.background = isDark
        ? 'rgba(56, 189, 248, ' + (0.15 + intensity * 0.75) + ')'
        : 'rgba(14, 116, 144, ' + (0.12 + intensity * 0.7) + ')';
    }
    if (total > 0) {
      var num = document.createElement('span');
      num.className = 'heatmap-num';
      num.textContent = total;
      num.style.color = isDark
        ? 'rgba(255,255,255,0.85)'
        : intensity >= 0.5
          ? 'rgba(255,255,255,0.9)'
          : 'rgba(0,0,0,0.7)';
      num.style.textShadow =
        isDark || intensity >= 0.5 ? '0 0 2px rgba(0,0,0,0.6)' : 'none';
      cell.appendChild(num);
    }
    cell.addEventListener('mouseenter', function (e) {
      tip.textContent = cellTipText(this);
      tip.style.display = 'block';
    });
    cell.addEventListener('mousemove', function (e) {
      tip.style.left = e.clientX + 12 + 'px';
      tip.style.top = e.clientY + 12 + 'px';
    });
    cell.addEventListener('mouseleave', function () {
      tip.style.display = 'none';
    });
    cell.addEventListener('focus', function () {
      showTipAt(this);
    });
    cell.addEventListener('blur', function () {
      tip.style.display = 'none';
    });
    return cell;
  }

  function hourLabel(h) {
    return h % 6 === 0 ? (h % 12 || 12) + (h < 12 ? 'a' : 'p') : '';
  }

  function makeHeader(text, role) {
    const hdr = document.createElement('div');
    hdr.className = 'heatmap-header';
    hdr.textContent = text || '';
    if (role) hdr.setAttribute('role', role);
    return hdr;
  }

  function makeRow() {
    const row = document.createElement('div');
    row.className = 'heatmap-row';
    row.setAttribute('role', 'row');
    return row;
  }

  // Arrow-key navigation for roving tabindex within a grid
  function addGridKeyNav(grid, rowCount, colCount) {
    grid.addEventListener('keydown', function (e) {
      var focused = document.activeElement;
      if (!focused || !focused.dataset.dow) return;
      var d = +focused.dataset.dow,
        h = +focused.dataset.hour;
      // Wide: rows=days(d), cols=hours(h); Narrow: rows=hours(h), cols=days(d)
      var isWide = grid.classList.contains('heatmap-wide');
      var row = isWide ? d : h,
        col = isWide ? h : d;
      if (e.key === 'ArrowRight') col = (col + 1) % colCount;
      else if (e.key === 'ArrowLeft') col = (col + colCount - 1) % colCount;
      else if (e.key === 'ArrowDown') row = (row + 1) % rowCount;
      else if (e.key === 'ArrowUp') row = (row + rowCount - 1) % rowCount;
      else if (e.key === 'Home') {
        row = 0;
        col = 0;
      } else if (e.key === 'End') {
        row = rowCount - 1;
        col = colCount - 1;
      } else return;
      e.preventDefault();
      var nd = isWide ? row : col,
        nh = isWide ? col : row;
      var next = grid.querySelector(
        '[data-dow="' + nd + '"][data-hour="' + nh + '"]',
      );
      if (next) {
        focused.setAttribute('tabindex', '-1');
        next.setAttribute('tabindex', '0');
        next.focus();
      }
    });
  }

  // Wide grid: rows = days, columns = hours (original layout)
  const wide = document.createElement('div');
  wide.className = 'heatmap-grid heatmap-wide';
  wide.setAttribute('role', 'grid');
  wide.setAttribute(
    'aria-label',
    'Release activity heatmap: days of week by hours',
  );
  var hdrRow = makeRow();
  hdrRow.appendChild(makeHeader('', 'columnheader'));
  for (let h = 0; h < 24; h++)
    hdrRow.appendChild(makeHeader(hourLabel(h), 'columnheader'));
  wide.appendChild(hdrRow);
  for (let d = 0; d < 7; d++) {
    var row = makeRow();
    const lbl = document.createElement('div');
    lbl.className = 'heatmap-row-label';
    lbl.setAttribute('role', 'rowheader');
    lbl.textContent = dayNames[d];
    row.appendChild(lbl);
    for (let h = 0; h < 24; h++)
      row.appendChild(makeCell(d, h, d === 0 && h === 0));
    wide.appendChild(row);
  }
  addGridKeyNav(wide, 7, 24);
  container.appendChild(wide);

  // Narrow grid: rows = hours, columns = days (transposed for mobile)
  const narrow = document.createElement('div');
  narrow.className = 'heatmap-grid heatmap-narrow';
  narrow.setAttribute('role', 'grid');
  narrow.setAttribute(
    'aria-label',
    'Release activity heatmap: hours by days of week',
  );
  hdrRow = makeRow();
  hdrRow.appendChild(makeHeader('', 'columnheader'));
  for (let d = 0; d < 7; d++)
    hdrRow.appendChild(makeHeader(dayNames[d], 'columnheader'));
  narrow.appendChild(hdrRow);
  for (let h = 0; h < 24; h++) {
    var row = makeRow();
    const lbl = document.createElement('div');
    lbl.className = 'heatmap-row-label';
    lbl.setAttribute('role', 'rowheader');
    lbl.textContent = hourLabel(h);
    row.appendChild(lbl);
    for (let d = 0; d < 7; d++)
      row.appendChild(makeCell(d, h, d === 0 && h === 0));
    narrow.appendChild(row);
  }
  addGridKeyNav(narrow, 24, 7);
  container.appendChild(narrow);

  // "Now" dot — highlight current US/Pacific day+hour in both grids
  try {
    var pacNow = new Date(
      new Date().toLocaleString('en-US', { timeZone: 'America/Los_Angeles' }),
    );
    var jsDow = pacNow.getDay(); // 0=Sun
    var nowDow = (jsDow + 6) % 7; // convert to 0=Mon
    var nowHour = pacNow.getHours();
    [wide, narrow].forEach(function (g) {
      var nowCell = g.querySelector(
        '[data-dow="' + nowDow + '"][data-hour="' + nowHour + '"]',
      );
      if (nowCell) {
        var dot = document.createElement('div');
        dot.className = 'heatmap-now';
        dot.title = 'Now (US/Pacific)';
        nowCell.appendChild(dot);
      }
    });
  } catch (e) {}

  // Legend
  const legend = document.createElement('div');
  legend.className = 'heatmap-legend';
  const lessLabel = document.createElement('span');
  lessLabel.textContent = 'Less';
  legend.appendChild(lessLabel);
  [0, 0.25, 0.5, 0.75, 1].forEach(function (intensity) {
    const swatch = document.createElement('div');
    swatch.className = 'heatmap-legend-cell';
    const dk = getTheme() === 'dark';
    swatch.style.background =
      intensity === 0
        ? dk
          ? 'rgba(255,255,255,0.03)'
          : 'rgba(0,0,0,0.03)'
        : dk
          ? 'rgba(56, 189, 248, ' + (0.15 + intensity * 0.75) + ')'
          : 'rgba(14, 116, 144, ' + (0.12 + intensity * 0.7) + ')';
    legend.appendChild(swatch);
  });
  const moreLabel = document.createElement('span');
  moreLabel.textContent = 'More';
  legend.appendChild(moreLabel);
  container.appendChild(legend);
})();

// Heatmap theme update helper
function updateHeatmapTheme() {
  const isDark = getTheme() === 'dark';
  const maxVal = Math.max(1, ...heatmapDowHour.flat());
  document.querySelectorAll('.heatmap-cell').forEach(function (cell) {
    const total = +cell.dataset.total;
    const intensity = total > 0 ? Math.sqrt(total / maxVal) : 0;
    if (total === 0) {
      cell.style.background = isDark
        ? 'rgba(255,255,255,0.03)'
        : 'rgba(0,0,0,0.03)';
    } else {
      cell.style.background = isDark
        ? 'rgba(56, 189, 248, ' + (0.15 + intensity * 0.75) + ')'
        : 'rgba(14, 116, 144, ' + (0.12 + intensity * 0.7) + ')';
    }
    var numEl = cell.querySelector('.heatmap-num');
    if (numEl) {
      numEl.style.color = isDark
        ? 'rgba(255,255,255,0.85)'
        : intensity >= 0.5
          ? 'rgba(255,255,255,0.9)'
          : 'rgba(0,0,0,0.7)';
      numEl.style.textShadow =
        isDark || intensity >= 0.5 ? '0 0 2px rgba(0,0,0,0.6)' : 'none';
    }
  });
  document
    .querySelectorAll('.heatmap-legend-cell')
    .forEach(function (swatch, i) {
      var intensity = [0, 0.25, 0.5, 0.75, 1][i];
      swatch.style.background =
        intensity === 0
          ? isDark
            ? 'rgba(255,255,255,0.03)'
            : 'rgba(0,0,0,0.03)'
          : isDark
            ? 'rgba(56, 189, 248, ' + (0.15 + intensity * 0.75) + ')'
            : 'rgba(14, 116, 144, ' + (0.12 + intensity * 0.7) + ')';
    });
}

